export interface CSVParserOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVParseError {
  row: number;
  message: string;
}

export interface CSVResult {
  headers: string[];
  rows: Array<Record<string, unknown>>;
  errors: CSVParseError[];
  filter: (predicate: (row: Record<string, unknown>) => boolean) => Array<Record<string, unknown>>;
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<unknown, Array<Record<string, unknown>>>;
}

const DEFAULT_OPTIONS: Required<CSVParserOptions> = {
  delimiter: ",",
  quoteChar: "\"",
  lineSeparator: "\n",
};

function detectLineSeparator(input: string, provided?: string): string {
  if (provided) {
    return provided;
  }
  return input.includes("\r\n") ? "\r\n" : "\n";
}

function coerceValue(value: string): unknown {
  const trimmed = value.trim();
  if (trimmed === "" || trimmed.toLowerCase() === "null") {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === "true") {
    return true;
  }
  if (lower === "false") {
    return false;
  }
  if (/^-?\d+$/.test(trimmed)) {
    return Number.parseInt(trimmed, 10);
  }
  if (/^-?(\d+\.\d*|\d*\.\d+)$/.test(trimmed)) {
    return Number.parseFloat(trimmed);
  }
  return value;
}

function parseRows(input: string, options: Required<CSVParserOptions>, errors: CSVParseError[]): string[][] {
  if (input.length === 0) {
    return [];
  }

  const rows: string[][] = [];
  let row: string[] = [];
  let field = "";
  let inQuotes = false;
  const delimiter = options.delimiter;
  const quoteChar = options.quoteChar;
  const lineSeparator = options.lineSeparator;
  let index = 0;
  let endedWithLineSeparator = false;

  while (index < input.length) {
    endedWithLineSeparator = false;
    const char = input[index];

    if (inQuotes) {
      if (char === quoteChar) {
        const nextChar = input[index + 1];
        if (nextChar === quoteChar) {
          field += quoteChar;
          index += 2;
          continue;
        }
        inQuotes = false;
        index += 1;
        continue;
      }
      field += char;
      index += 1;
      continue;
    }

    if (char === quoteChar) {
      inQuotes = true;
      index += 1;
      continue;
    }

    if (input.startsWith(lineSeparator, index)) {
      row.push(field);
      rows.push(row);
      row = [];
      field = "";
      index += lineSeparator.length;
      endedWithLineSeparator = true;
      continue;
    }

    if (input.startsWith(delimiter, index)) {
      row.push(field);
      field = "";
      index += delimiter.length;
      continue;
    }

    field += char;
    index += 1;
  }

  if (inQuotes) {
    const rowNumber = rows.length + 1;
    errors.push({ row: rowNumber, message: "Unclosed quoted field" });
  }

  if (!endedWithLineSeparator || row.length > 0 || field.length > 0) {
    row.push(field);
    rows.push(row);
  }

  return rows;
}

export function parseCSV(input: string, options: CSVParserOptions = {}): CSVResult {
  const resolvedOptions: Required<CSVParserOptions> = {
    delimiter: options.delimiter ?? DEFAULT_OPTIONS.delimiter,
    quoteChar: options.quoteChar ?? DEFAULT_OPTIONS.quoteChar,
    lineSeparator: detectLineSeparator(input, options.lineSeparator ?? undefined),
  };

  const errors: CSVParseError[] = [];
  const rawRows = parseRows(input, resolvedOptions, errors);

  if (rawRows.length === 0) {
    return {
      headers: [],
      rows: [],
      errors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const headers = rawRows[0].map((header) => header.trim());
  const rows: Array<Record<string, unknown>> = [];

  for (let i = 1; i < rawRows.length; i += 1) {
    const row = rawRows[i];
    if (row.length !== headers.length) {
      errors.push({
        row: i + 1,
        message: `Row has ${row.length} fields but expected ${headers.length}.`,
      });
    }

    const record: Record<string, unknown> = {};
    for (let colIndex = 0; colIndex < headers.length; colIndex += 1) {
      const header = headers[colIndex] ?? "";
      const value = row[colIndex] ?? "";
      record[header] = coerceValue(value);
    }
    rows.push(record);
  }

  return {
    headers,
    rows,
    errors,
    filter: (predicate) => rows.filter(predicate),
    sum: (column) =>
      rows.reduce((total, current) => {
        const value = current[column];
        return typeof value === "number" && Number.isFinite(value) ? total + value : total;
      }, 0),
    average: (column) => {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number" && Number.isFinite(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count: () => rows.length,
    groupBy: (column) => {
      const grouped = new Map<unknown, Array<Record<string, unknown>>>();
      for (const row of rows) {
        const key = row[column];
        const existing = grouped.get(key);
        if (existing) {
          existing.push(row);
        } else {
          grouped.set(key, [row]);
        }
      }
      return grouped;
    },
  };
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(message);
  }
}

function assertEqual<T>(actual: T, expected: T, message: string): void {
  if (actual !== expected) {
    throw new Error(`${message}. Expected ${expected} but got ${actual}`);
  }
}

function testBasicParsing(): void {
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertEqual(result.headers.length, 2, "Header length should be 2");
  assertEqual(result.rows.length, 2, "Rows length should be 2");
  assertEqual(result.rows[0].name as string, "Alice", "First row name should be Alice");
  assertEqual(result.rows[1].age as number, 25, "Second row age should be 25");
}

function testQuotedFieldsWithCommas(): void {
  const input = "name,notes\nAlice,\"hello, world\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].notes as string, "hello, world", "Quoted field should include comma");
}

function testEscapedQuotes(): void {
  const input = "name,quote\nAlice,\"She said \"\"hi\"\"\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].quote as string, "She said \"hi\"", "Escaped quotes should be parsed");
}

function testCustomDelimiters(): void {
  const input = "name|age|active\nAlice|30|true";
  const result = parseCSV(input, { delimiter: "|" });
  assertEqual(result.rows[0].age as number, 30, "Custom delimiter should work");
  assertEqual(result.rows[0].active as boolean, true, "Boolean coercion should work");
}

function testTypeCoercion(): void {
  const input = "int,float,bool,nullish,empty,string\n42,3.14,TRUE,NULL,,hello";
  const result = parseCSV(input);
  const row = result.rows[0];
  assertEqual(row.int as number, 42, "Integer coercion should work");
  assertEqual(row.float as number, 3.14, "Float coercion should work");
  assertEqual(row.bool as boolean, true, "Boolean coercion should work");
  assertEqual(row.nullish as null, null, "Null coercion should work");
  assertEqual(row.empty as null, null, "Empty string should be null");
  assertEqual(row.string as string, "hello", "String should stay string");
}

function testMalformedRowErrors(): void {
  const input = "a,b,c\n1,2\n3,4,5,6";
  const result = parseCSV(input);
  assertEqual(result.errors.length, 2, "Should collect errors for malformed rows");
  assertEqual(result.errors[0].row, 2, "First error row should be 2");
  assertEqual(result.errors[1].row, 3, "Second error row should be 3");
}

function testFilterFunctionality(): void {
  const input = "name,age\nAlice,30\nBob,25\nCharlie,30";
  const result = parseCSV(input);
  const filtered = result.filter((row) => row.age === 30);
  assertEqual(filtered.length, 2, "Filter should return matching rows");
}

function testAggregationMethods(): void {
  const input = "name,score\nAlice,10\nBob,20\nCharlie,30";
  const result = parseCSV(input);
  assertEqual(result.sum("score"), 60, "Sum should be 60");
  assertEqual(result.average("score"), 20, "Average should be 20");
  assertEqual(result.count(), 3, "Count should be 3");
  const grouped = result.groupBy("score");
  assertEqual(grouped.get(10)?.length ?? 0, 1, "GroupBy should group rows");
}

function testEdgeCases(): void {
  const empty = parseCSV("");
  assertEqual(empty.headers.length, 0, "Empty input should have no headers");
  assertEqual(empty.rows.length, 0, "Empty input should have no rows");

  const singleColumn = parseCSV("value\n1\n2");
  assertEqual(singleColumn.rows.length, 2, "Single column should parse rows");
  assertEqual(singleColumn.rows[1].value as number, 2, "Single column should parse values");

  const singleRow = parseCSV("a,b\n1,2");
  assertEqual(singleRow.rows.length, 1, "Single row should parse");

  const largeField = "a".repeat(10000);
  const largeInput = `col\n\"${largeField}\"`;
  const largeResult = parseCSV(largeInput);
  assertEqual(largeResult.rows[0].col as string, largeField, "Large fields should parse");
}

const tests: Array<() => void> = [
  testBasicParsing,
  testQuotedFieldsWithCommas,
  testEscapedQuotes,
  testCustomDelimiters,
  testTypeCoercion,
  testMalformedRowErrors,
  testFilterFunctionality,
  testAggregationMethods,
  testEdgeCases,
];

let passed = 0;
for (const test of tests) {
  try {
    test();
    passed += 1;
  } catch (error) {
    console.error(`Test failed: ${test.name}`);
    throw error;
  }
}

console.log(`All tests passed: ${passed}/${tests.length}`);

